// Build the ICS content properly
const title = $('Webhook - Create Task').first().json.body.title;
const description = $('Webhook - Create Task').first().json.body.description || '';
const taskId = Date.now();

// Format current date for DTSTAMP
const now = new Date();
const year = now.getUTCFullYear();
const month = String(now.getUTCMonth() + 1).padStart(2, '0');
const day = String(now.getUTCDate()).padStart(2, '0');
const hours = String(now.getUTCHours()).padStart(2, '0');
const minutes = String(now.getUTCMinutes()).padStart(2, '0');
const seconds = String(now.getUTCSeconds()).padStart(2, '0');
const dtstamp = `${year}${month}${day}T${hours}${minutes}${seconds}Z`;

const icsBody = `BEGIN:VCALENDAR
VERSION:2.0
PRODID:-//n8n//Nextcloud//EN
BEGIN:VTODO
UID:n8n-task-${taskId}
DTSTAMP:${dtstamp}
SUMMARY:${title}
DESCRIPTION:${description}
STATUS:NEEDS-ACTION
END:VTODO
END:VCALENDAR`;

return [{ json: { nextcloudUrl: $('Set Config').first().json.nextcloudUrl, nextcloudUser: $('Set Config').first().json.nextcloudUser, icsBody } }];

const response = $input.first();

if (response.json.statusCode === 201 || response.json.statusCode === 204 || !response.json.error) {
  return [{
    json: {
      success: true,
      message: 'Task created successfully!',
      task: {
        title: $('Webhook - Create Task').first().json.body.title,
        description: $('Webhook - Create Task').first().json.body.description || null
      }
    }
  }];
} else {
  return [{
    json: {
      success: false,
      message: 'Failed to create task',
      error: response.json
    }
  }];
}
